import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Order } from '../../core/models';

/**
 * Storefront order detail (`orders/:id`, authGuard). Line items, ship-to, totals,
 * and status. service_agent wires ApiService.getOrder(id) in ngOnInit().
 */
@Component({
  selector: 'app-order-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './order-detail.component.html',
  styleUrl: './order-detail.component.css',
})
export class OrderDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  // Mock orders — service_agent replaces with ApiService.getOrder(id).
  readonly orders = signal<Order[]>([
    {
      id: 'o1002',
      userId: 'demo-shopper',
      status: 'placed',
      shipName: 'Ada Lovelace',
      shipAddress: '123 Analytical Engine Way, London, UK',
      totalCents: 25300,
      createdAt: '2026-07-11T14:20:00.000Z',
      items: [
        { id: 'oi1', orderId: 'o1002', productId: 'p1', qty: 1, unitPriceCents: 18900,
          product: { id: 'p1', name: 'Aurora Wireless Headphones', description: '', priceCents: 18900,
            imageUrl: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=200&q=80', stockQty: 24 } },
        { id: 'oi2', orderId: 'o1002', productId: 'p2', qty: 2, unitPriceCents: 3200,
          product: { id: 'p2', name: 'Terra Insulated Bottle', description: '', priceCents: 3200,
            imageUrl: 'https://images.unsplash.com/photo-1602143407151-7111542de6e8?w=200&q=80', stockQty: 120 } },
      ],
    },
  ]);

  orderId = '';

  readonly order = computed<Order | undefined>(() =>
    this.orders().find((o) => o.id === this.orderId) ?? this.orders()[0],
  );

  constructor(private api: ApiService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.orderId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loading.set(true);
    this.error.set(null);
    this.api.getOrder(this.orderId).subscribe({
      next: (order) => {
        this.orders.set([order]);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load this order.');
        this.loading.set(false);
      },
    });
  }

  money(cents: number): string {
    return '$' + (cents / 100).toFixed(2);
  }
}
